# cards.py — 64 карты оракула "Горизонт Событий"
# 8 коридоров × 8 дверей

CARDS = [
    # ── КОРИДОР 1 — ПРИВЯЗАННОСТЬ ──
    {"id":"01","name":"Одиночество","description":"Коридор Привязанности · Дверь 1\nМожно ли опираться на других","meaning":"Ты здесь один. Не потому что никого нет — а потому что контакт кажется невозможным. Это старое чувство, не сегодняшнее. Оно пришло раньше чем ты научилась говорить о нём словами. Позволь себе просто признать — мне одиноко. Не объяснять. Не исправлять. Просто знать."},
    {"id":"02","name":"Голод","description":"Коридор Привязанности · Дверь 2\nМожно ли опираться на других","meaning":"Ты хочешь больше чем позволяешь себе просить. Близости, внимания, тепла, присутствия. Где-то внутри живёт убеждение что хотеть слишком много — опасно или стыдно. Эта дверь спрашивает — что ты на самом деле хочешь от этого человека или этой ситуации?"},
    {"id":"03","name":"Недоверие","description":"Коридор Привязанности · Дверь 3\nМожно ли опираться на других","meaning":"Ты уже знаешь чем это заканчивается. Или думаешь что знаешь. Осторожность которая когда-то тебя защитила — сейчас держит тебя на расстоянии от того что тебе нужно. Эта дверь не говорит — доверяй всем. Она спрашивает — кому здесь можно доверять хоть немного?"},
    {"id":"04","name":"Слияние","description":"Коридор Привязанности · Дверь 4\nМожно ли опираться на других","meaning":"Ты перестаёшь чувствовать где заканчиваешься ты и начинается другой. Его настроение становится твоим. Его тревога — твоей. Это не любовь — это потеря себя в другом. Эта дверь возвращает тебя к вопросу — что сейчас чувствую именно я?"},
    {"id":"05","name":"Дистанция","description":"Коридор Привязанности · Дверь 5\nМожно ли опираться на других","meaning":"Ты умеешь быть рядом — но не слишком близко. Всегда чуть в стороне. Это безопаснее. Но что-то в этой безопасности стоит тебе дорого. Эта дверь спрашивает — от чего именно ты держишь дистанцию прямо сейчас?"},
    {"id":"06","name":"Возврат","description":"Коридор Привязанности · Дверь 6\nМожно ли опираться на других","meaning":"Ты снова и снова возвращаешься к одному и тому же человеку, паттерну, динамике. Не потому что не знаешь лучшего — а потому что знакомое ощущается как дом, даже если дом был неспокойным. Эта дверь спрашивает — что ты ищешь в этом возврате?"},
    {"id":"07","name":"Опора","description":"Коридор Привязанности · Дверь 7\nМожно ли опираться на других","meaning":"Впервые или снова — ты чувствуешь что можно опереться. Не исчезнуть в другом, не потерять себя — а просто получить поддержку. Это непривычно. Может быть страшно. Эта дверь говорит — позволь."},
    {"id":"08","name":"Контакт","description":"Коридор Привязанности · Дверь 8\nМожно ли опираться на других","meaning":"Ты здесь. Другой здесь. Между вами — живое пространство, не слияние и не дистанция. Это и есть настоящая близость. Не навсегда — прямо сейчас. Эта дверь говорит — оставайся в этом моменте."},
    # ── КОРИДОР 2 — ТЕНЬ ──
    {"id":"09","name":"Отрицание","description":"Коридор Тени · Дверь 1\nВсё что я не хочу в себе видеть","meaning":"Ты уверена что этого в тебе нет. Именно поэтому так раздражает в других. Тень всегда громче всего говорит через реакции — не через признания. Эта дверь спрашивает — что тебя сейчас больше всего раздражает в другом человеке?"},
    {"id":"10","name":"Стыд","description":"Коридор Тени · Дверь 2\nВсё что я не хочу в себе видеть","meaning":"Эта часть тебя была отвергнута так рано что ты уже не помнишь когда решила её спрятать. Может быть тебе сказали что это некрасиво, неудобно, слишком много. Она не исчезла — она просто ждёт. Эта дверь спрашивает — что в себе ты никогда не показываешь?"},
    {"id":"11","name":"Проекция","description":"Коридор Тени · Дверь 3\nВсё что я не хочу в себе видеть","meaning":"Ты видишь в другом то что живёт в тебе. Его жадность, его трусость, его эгоизм — или его свобода, его смелость, его лёгкость. Проекция работает в обе стороны — мы проецируем не только тёмное но и непризнанный свет. Эта дверь спрашивает — что ты видишь в этом человеке что на самом деле твоё?"},
    {"id":"12","name":"Маска","description":"Коридор Тени · Дверь 4\nВсё что я не хочу в себе видеть","meaning":"Ты так долго играла эту роль что уже не всегда знаешь где роль а где ты. Хорошая девочка. Сильная женщина. Та которая справляется. Маска не враг — она защищала. Но сейчас она жмёт. Эта дверь спрашивает — что ты чувствуешь когда никто не смотрит?"},
    {"id":"13","name":"Ярость","description":"Коридор Тени · Дверь 5\nВсё что я не хочу в себе видеть","meaning":"Она живёт глубже чем ты думаешь. Может быть ты называешь её усталостью, обидой, разочарованием — потому что ярость казалась неприемлемой. Но ярость это энергия. Она указывает где была нарушена граница, где было предательство, где тебя не увидели. Эта дверь спрашивает — на что ты на самом деле злишься?"},
    {"id":"14","name":"Золотая Тень","description":"Коридор Тени · Дверь 6\nВсё что я не хочу в себе видеть","meaning":"Не всё что спрятано — тёмное. Иногда в Тени живёт твой дар, твоя красота, твоя сила — всё что тебе не позволили присвоить. Скромность как запрет на величие. Эта дверь спрашивает — что в себе ты боишься признать как достоинство?"},
    {"id":"15","name":"Встреча","description":"Коридор Тени · Дверь 7\nВсё что я не хочу в себе видеть","meaning":"Ты смотришь на свою Тень — и не убегаешь. Это не значит что тебе нравится то что видишь. Это значит что ты достаточно сильна чтобы выдержать правду о себе. Юнг говорил — встреча с Тенью это моральное достижение. Эта дверь говорит — ты уже здесь. Смотри."},
    {"id":"16","name":"Интеграция","description":"Коридор Тени · Дверь 8\nВсё что я не хочу в себе видеть","meaning":"То что было отвергнуто возвращается домой. Не побеждённым — принятым. Твоя ярость становится силой. Твой стыд становится состраданием. Твоя слабость становится уязвимостью которая соединяет. Эта дверь говорит — ты становишься целой."},
    # ── КОРИДОР 3 — ТЕЛО ──
    {"id":"17","name":"Онемение","description":"Коридор Тела · Дверь 1\nЧто моё тело знает, что я ещё не признала","meaning":"Ты перестала чувствовать. Не сразу — постепенно. Сначала было слишком больно, потом тело научилось не чувствовать вообще. Это была защита. Она сработала. Но теперь ты не чувствуешь и хорошее тоже. Эта дверь спрашивает — где в теле ты сейчас ничего не ощущаешь?"},
    {"id":"18","name":"Сигнал","description":"Коридор Тела · Дверь 2\nЧто моё тело знает, что я ещё не признала","meaning":"Тело говорит раньше чем ум успевает подумать. Сжатое горло. Тяжесть в груди. Напряжение в плечах которое не уходит. Это не болезнь — это послание. Эта дверь спрашивает — что твоё тело пытается тебе сказать прямо сейчас?"},
    {"id":"19","name":"Граница Тела","description":"Коридор Тела · Дверь 3\nЧто моё тело знает, что я ещё не признала","meaning":"Ты согласилась когда тело говорило нет. Может быть давно, может быть недавно. Граница живёт в теле раньше чем в словах — как сжатие, как отступление, как желание исчезнуть. Эта дверь спрашивает — где твоё тело говорит нет, а ты ещё не услышала?"},
    {"id":"20","name":"Память Тела","description":"Коридор Тела · Дверь 4\nЧто моё тело знает, что я ещё не признала","meaning":"Тело помнит то что ум забыл или решил не помнить. Ван дер Колк называл это — тело ведёт счёт. Не чтобы наказать — чтобы завершить незавершённое. Эта дверь спрашивает — какое старое ощущение живёт в тебе прямо сейчас?"},
    {"id":"21","name":"Голос Тела","description":"Коридор Тела · Дверь 5\nЧто моё тело знает, что я ещё не признала","meaning":"Ты проглотила слова. Много раз. Горло сжималось — и ты молчала. Потому что говорить было опасно, неудобно, бесполезно. Голос это тело — не только мысль. Эта дверь спрашивает — что ты давно хочешь сказать вслух?"},
    {"id":"22","name":"Усталость","description":"Коридор Тела · Дверь 6\nЧто моё тело знает, что я ещё не признала","meaning":"Не та усталость которая проходит после сна. Глубокая — от долгого несения, от хронического напряжения, от жизни в режиме выживания. Тело устало быть в боевой готовности. Эта дверь говорит — можно остановиться. Прямо сейчас. На одну минуту."},
    {"id":"23","name":"Удовольствие","description":"Коридор Тела · Дверь 7\nЧто моё тело знает, что я ещё не признала","meaning":"Ты разрешаешь себе получать удовольствие? Не заслуженное — просто так. Тепло, вкус, движение, покой. Для многих людей удовольствие связано со стыдом или виной. Эта дверь спрашивает — что доставляет тебе радость просто потому что ты живая?"},
    {"id":"24","name":"Дом","description":"Коридор Тела · Дверь 8\nЧто моё тело знает, что я ещё не признала","meaning":"Тело это твой единственный настоящий дом. Не временное жильё — постоянный адрес. Всё путешествие происходит здесь. Эта дверь говорит — вернись. Почувствуй стопы на полу, дыхание в груди, вес своего тела. Ты здесь. Ты дома."},
    # ── КОРИДОР 4 — ИДЕНТИЧНОСТЬ ──
    {"id":"25","name":"Роль","description":"Коридор Идентичности · Дверь 1\nКто я когда рушится привычный образ себя","meaning":"Ты так долго была чьей-то мамой, дочерью, женой, коллегой, помощницей — что забыла спросить себя кто ты без этих слов. Роль это не ложь — но это не вся правда. Эта дверь спрашивает — кто ты когда никому ничего не должна?"},
    {"id":"26","name":"Разрушение","description":"Коридор Идентичности · Дверь 2\nКто я когда рушится привычный образ себя","meaning":"Что-то рухнуло. Отношения, работа, образ себя, план на жизнь. Это больно — и это не конец. Юнг говорил — психика разрушает то что стало слишком тесным. Как змея сбрасывает кожу. Эта дверь спрашивает — что именно разрушилось и не давало тебе дышать?"},
    {"id":"27","name":"Чужое","description":"Коридор Идентичности · Дверь 3\nКто я когда рушится привычный образ себя","meaning":"Ты живёшь чужой жизнью. Чужими ценностями, чужими ожиданиями, чужим сценарием. Не из слабости — из любви или из страха потерять принятие. Эта дверь спрашивает — что в твоей жизни на самом деле не твоё?"},
    {"id":"28","name":"Пустота","description":"Коридор Идентичности · Дверь 4\nКто я когда рушится привычный образ себя","meaning":"Старое ушло — новое ещё не пришло. Это странное состояние между. Не депрессия и не свобода — а пространство без привычных ориентиров. Юнг называл это liminality — пороговое состояние. Эта дверь говорит — пустота это не отсутствие. Это место где рождается новое."},
    {"id":"29","name":"Сравнение","description":"Коридор Идентичности · Дверь 5\nКто я когда рушится привычный образ себя","meaning":"Ты меряешь себя другими — и всегда находишь недостачу. Или наоборот — возвышаешься над другими чтобы почувствовать себя в безопасности. Оба движения уводят от себя. Эта дверь спрашивает — кто ты без сравнения с кем-либо?"},
    {"id":"30","name":"Прошлое","description":"Коридор Идентичности · Дверь 6\nКто я когда рушится привычный образ себя","meaning":"Ты до сих пор живёшь событием которое давно закончилось. Оно определяет кто ты, что можешь, чего заслуживаешь. Прошлое реально — но оно не приговор. Эта дверь спрашивает — какое старое решение о себе ты готова пересмотреть?"},
    {"id":"31","name":"Проявление","description":"Коридор Идентичности · Дверь 7\nКто я когда рушится привычный образ себя","meaning":"Что-то новое просится наружу. Новая часть тебя — непривычная, может быть пугающая, может быть радостная. Она не вписывается в старый образ. Это хороший знак. Эта дверь спрашивает — что в тебе сейчас хочет быть увиденным?"},
    {"id":"32","name":"Своя","description":"Коридор Идентичности · Дверь 8\nКто я когда рушится привычный образ себя","meaning":"Ты узнаёшь себя. Не идеальную, не законченную — живую, противоречивую, настоящую. Это не финал пути — это момент когда ты перестаёшь искать себя снаружи. Эта дверь говорит — ты уже есть. Этого достаточно."},
    # ── КОРИДОР 5 — СИЛА ──
    {"id":"33","name":"Беспомощность","description":"Коридор Силы · Дверь 1\nГде я на самом деле могу выбирать","meaning":"Ты чувствуешь что ничего не можешь изменить. Это ощущение знакомо — оно было правдой когда ты была маленькой и зависела от других. Но сейчас ты не там. Эта дверь спрашивает — что в этой ситуации на самом деле в твоих руках, даже если это очень маленькое?"},
    {"id":"34","name":"Контроль","description":"Коридор Силы · Дверь 2\nГде я на самом деле могу выбирать","meaning":"Ты держишь всё под контролем — потому что когда-то отсутствие контроля было опасным. Контроль это была твоя сила. Но сейчас он стоит тебе энергии которой могло бы хватить на жизнь. Эта дверь спрашивает — что ты можешь отпустить прямо сейчас?"},
    {"id":"35","name":"Согласие","description":"Коридор Силы · Дверь 3\nГде я на самом деле могу выбирать","meaning":"Ты сказала да когда хотела сказать нет. Не один раз — много раз. Из страха, из вежливости, из привычки. Каждое такое согласие немного уменьшало тебя. Эта дверь спрашивает — где ты сейчас говоришь да, имея в виду нет?"},
    {"id":"36","name":"Жертва","description":"Коридор Силы · Дверь 4\nГде я на самом деле могу выбирать","meaning":"Ты отдаёшь больше чем получаешь — и называешь это любовью или долгом. Иногда это так. Но иногда за жертвенностью прячется страх — что если не отдавать, тебя не захотят. Эта дверь спрашивает — из чего ты сейчас отдаёшь? Из полноты или из страха?"},
    {"id":"37","name":"Голос Силы","description":"Коридор Силы · Дверь 5\nГде я на самом деле могу выбирать","meaning":"Ты знаешь что думаешь — но не говоришь. Слова останавливаются где-то между мыслью и ртом. Потому что однажды твой голос был неудобен, опасен, отвергнут. Эта дверь спрашивает — что ты хочешь сказать тому человеку или в той ситуации которая тебя привела сюда?"},
    {"id":"38","name":"Выбор","description":"Коридор Силы · Дверь 6\nГде я на самом деле могу выбирать","meaning":"Ты уже выбираешь — даже когда кажется что выбора нет. Молчать это выбор. Остаться это выбор. Не действовать это выбор. Осознанность не в том чтобы иметь все варианты — а в том чтобы видеть что ты выбираешь. Эта дверь спрашивает — какой выбор ты делаешь прямо сейчас?"},
    {"id":"39","name":"Граница","description":"Коридор Силы · Дверь 7\nГде я на самом деле могу выбирать","meaning":"Не стена — а живая линия между тобой и миром. Граница это не агрессия. Это уважение к себе выраженное вслух. Она говорит — вот где я, вот что мне подходит, вот что нет. Эта дверь спрашивает — какую границу ты давно хочешь обозначить?"},
    {"id":"40","name":"Действие","description":"Коридор Силы · Дверь 8\nГде я на самом деле могу выбирать","meaning":"Не грандиозное — маленькое. Один шаг который ты откладывала. Сила это не отсутствие страха — это движение несмотря на него. Эта дверь говорит — сделай одно действие сегодня. Самое маленькое из возможных. Оно изменит направление."},
    # ── КОРИДОР 6 — ПОТЕРЯ ──
    {"id":"41","name":"Отрицание Потери","description":"Коридор Потери · Дверь 1\nЧто я ещё не отпустила","meaning":"Этого не должно было случиться. Ты до сих пор внутри споришь с реальностью — перебираешь что могло быть иначе, где была точка где всё могло пойти по-другому. Это не слабость — это первый слой горя. Эта дверь спрашивает — что ты до сих пор не можешь принять как свершившееся?"},
    {"id":"42","name":"Гнев","description":"Коридор Потери · Дверь 2\nЧто я ещё не отпустила","meaning":"Под потерей почти всегда живёт злость. На человека который ушёл. На себя. На жизнь которая так устроена. Гнев в горе это не жестокость — это любовь которой некуда идти. Эта дверь спрашивает — на кого или на что ты злишься в этой потере?"},
    {"id":"43","name":"Вина","description":"Коридор Потери · Дверь 3\nЧто я ещё не отпустила","meaning":"Ты убеждена что могла предотвратить. Должна была сказать, сделать, остановить, не делать. Вина это попытка психики сохранить контроль над тем что было неподвластно. Эта дверь спрашивает — что ты готова себе простить?"},
    {"id":"44","name":"Незавершённое","description":"Коридор Потери · Дверь 4\nЧто я ещё не отпустила","meaning":"Остались слова которые не были сказаны. Объятие которого не было. Разговор который так и не случился. Незавершённое не исчезает — оно живёт внутри и ждёт. Эта дверь спрашивает — что ты хочешь сказать тому кого или что потеряла?"},
    {"id":"45","name":"Пустое Место","description":"Коридор Потери · Дверь 5\nЧто я ещё не отпустила","meaning":"Там где был человек, отношение, роль, мечта — теперь пространство. Ты обходишь его стороной. Не смотришь в ту сторону. Но оно есть. Эта дверь говорит — можно посмотреть на это место прямо. Не чтобы заполнить — а чтобы признать что оно есть."},
    {"id":"46","name":"Память","description":"Коридор Потери · Дверь 6\nЧто я ещё не отпустила","meaning":"Ты держишься за воспоминания как за последнее что осталось. Боишься что если отпустишь боль — отпустишь и их. Но память не исчезает когда уходит острое горе. Она просто меняет форму — из раны в часть тебя. Эта дверь говорит — можно помнить без боли. Не сразу. Но можно."},
    {"id":"47","name":"Продолжение","description":"Коридор Потери · Дверь 7\nЧто я ещё не отпустила","meaning":"Жизнь продолжается — и ты не знаешь как к этому относиться. Смеяться снова кажется предательством. Радоваться — слишком рано. Но продолжение это не забвение. Это то что потерянное хотело бы для тебя. Эта дверь спрашивает — что в тебе хочет жить дальше?"},
    {"id":"48","name":"Отпускание","description":"Коридор Потери · Дверь 8\nЧто я ещё не отпустила","meaning":"Не забыть. Не вычеркнуть. Не сделать вид что не было. Отпустить — это сказать внутри: это было. Это важно. Это часть меня. И я иду дальше неся это как опыт а не как груз. Эта дверь говорит — ты можешь отпустить и всё равно любить то что было."},
    # ── КОРИДОР 7 — ТВОРЧЕСТВО ──
    {"id":"49","name":"Молчание","description":"Коридор Творчества · Дверь 1\nЧто во мне просит быть созданным","meaning":"Что-то в тебе давно хочет выразить себя — и молчит. Не потому что нечего сказать. А потому что однажды тебе дали понять что твой голос, твой рисунок, твоя идея — недостаточно хороши. Ты поверила. Эта дверь спрашивает — что ты перестала создавать после того как кто-то не оценил?"},
    {"id":"50","name":"Перфекционизм","description":"Коридор Творчества · Дверь 2\nЧто во мне просит быть созданным","meaning":"Ты не начинаешь потому что уже знаешь что будет недостаточно хорошо. Перфекционизм это не высокие стандарты — это страх оценки в красивой упаковке. Он убивает больше творчества чем любая критика. Эта дверь спрашивает — что ты создала бы если бы никто никогда не увидел?"},
    {"id":"51","name":"Разрешение","description":"Коридор Творчества · Дверь 3\nЧто во мне просит быть созданным","meaning":"Ты ждёшь что кто-то придёт и скажет — теперь можно. Теперь ты достаточно готова, достаточно талантлива, достаточно знаешь. Этот человек не придёт. Разрешение можно только дать себе самой. Эта дверь говорит — можно. Прямо сейчас. Именно тебе."},
    {"id":"52","name":"Поток","description":"Коридор Творчества · Дверь 4\nЧто во мне просит быть созданным","meaning":"Бывают моменты когда ты создаёшь и забываешь о времени. Когда не ты делаешь — а через тебя делается. Юнг называл это контактом с бессознательным. Это не случайность и не талант избранных — это состояние доступное каждому кто перестаёт контролировать. Эта дверь спрашивает — когда ты последний раз была в потоке?"},
    {"id":"53","name":"Страх Видимости","description":"Коридор Творчества · Дверь 5\nЧто во мне просит быть созданным","meaning":"Создать можно. Показать — страшно. Потому что когда показываешь — становишься уязвимой. Тебя можно увидеть, оценить, отвергнуть. Но именно видимость превращает творчество в контакт. Эта дверь спрашивает — кому ты боишься показать то что создаёшь?"},
    {"id":"54","name":"Материал","description":"Коридор Творчества · Дверь 6\nЧто во мне просит быть созданным","meaning":"У тебя есть материал — твоя жизнь, твои раны, твои прозрения, твои сны. Всё что ты пережила это не багаж — это сырьё. Самые живые работы рождаются из самого личного. Эта дверь спрашивает — какой опыт в тебе просит стать чем-то созданным?"},
    {"id":"55","name":"Форма","description":"Коридор Творчества · Дверь 7\nЧто во мне просит быть созданным","meaning":"Идея ищет форму. Образ ищет слово, цвет, звук, движение. Не каждая идея знает заранее в чём хочет родиться. Иногда нужно попробовать несколько форм пока не почувствуешь — вот оно. Эта дверь спрашивает — в какой форме хочет выразить себя то что живёт внутри тебя?"},
    {"id":"56","name":"Дар","description":"Коридор Творчества · Дверь 8\nЧто во мне просит быть созданным","meaning":"То что ты создаёшь — не только твоё. Оно становится чьим-то опытом, чьим-то утешением, чьим-то озарением. Творчество это акт щедрости даже когда кажется эгоистичным. Эта дверь говорит — то что ты несёшь внутри нужно кому-то снаружи. Создай это."},
    # ── КОРИДОР 8 — САМОСТЬ ──
    {"id":"57","name":"Зов","description":"Коридор Самости · Дверь 1\nКем я становлюсь","meaning":"Что-то внутри тебя знает куда идти — даже когда ум не знает. Это не голос и не мысль — скорее тяготение. Как компас который всегда указывает в одну сторону сколько бы ты ни поворачивалась. Эта дверь спрашивает — что в тебе давно тянет в определённом направлении и ты продолжаешь игнорировать?"},
    {"id":"58","name":"Противоречие","description":"Коридор Самости · Дверь 2\nКем я становлюсь","meaning":"В тебе живут части которые хотят разного. Одна хочет покоя — другая приключений. Одна хочет близости — другая свободы. Это не патология — это полнота. Самость не выбирает одну часть и отвергает другую. Она держит обе. Эта дверь спрашивает — какие два противоположных желания живут в тебе прямо сейчас?"},
    {"id":"59","name":"Кризис","description":"Коридор Самости · Дверь 3\nКем я становлюсь","meaning":"Всё рухнуло или рушится. Юнг говорил — Самость приходит через кризис. Не потому что жестока — а потому что старая оболочка стала слишком тесной. То что разрушается — уже не служит тебе. Эта дверь спрашивает — что в твоей жизни разрушается и, возможно, должно разрушиться?"},
    {"id":"60","name":"Символ","description":"Коридор Самости · Дверь 4\nКем я становлюсь","meaning":"Образ который преследует тебя — в снах, в случайных встречах, в том что притягивает взгляд. Самость говорит символами раньше чем словами. Это не суеверие — это язык глубины. Эта дверь спрашивает — какой образ или символ появляется в твоей жизни снова и снова?"},
    {"id":"61","name":"Одиночество Пути","description":"Коридор Самости · Дверь 5\nКем я становлюсь","meaning":"Никто не может пройти этот путь за тебя или вместо тебя. Можно идти рядом — но не вместо. В какой-то момент становится ясно что самое важное происходит внутри и не передаётся словами. Это одиноко — и это честно. Эта дверь говорит — то что ты несёшь внутри не нужно объяснять. Достаточно нести."},
    {"id":"62","name":"Принятие","description":"Коридор Самости · Дверь 6\nКем я становлюсь","meaning":"Не смирение и не капитуляция. Принятие это когда перестаёшь воевать с тем что есть — и начинаешь работать с реальностью а не с тем какой она должна была быть. Это освобождает огромное количество энергии. Эта дверь спрашивает — с чем ты до сих пор воюешь внутри себя?"},
    {"id":"63","name":"Целостность","description":"Коридор Самости · Дверь 7\nКем я становлюсь","meaning":"Не идеальность — целостность. Твоя Тень принята. Твоя уязвимость признана. Твои противоречия не разрешены — а удержаны вместе. Ты не стала лучше — ты стала настоящей. Эта дверь говорит — всё что ты пережила, всё что ты несёшь, всё что ты есть — это и есть ты. Этого достаточно."},
    {"id":"64","name":"Individuation","description":"Коридор Самости · Дверь 8\nКем я становлюсь","meaning":"Это слово Юнга для процесса становления собой. Не однажды — всю жизнь. Каждый кризис, каждая встреча с Тенью, каждое принятие — шаг. Ты не достигаешь Самости как пункта назначения. Ты живёшь в направлении неё. Эта дверь говорит — ты уже на пути. Ты уже идёшь. Этого достаточно чтобы продолжать."},
]
